// trades that depend on others (e.g. ฝ้ารอไฟ, สีรอผนัง)
const deps = {ceiling:['electrical'], paint:['plaster'], aircon:['electrical'], kitchen:['plumbing','electrical']};
const busy = $input.all().filter(x=>x.json.status==='ติด').map(x=>x.json.trade);
const impacted = Object.entries(deps).filter(([k,v])=>v.some(t=>busy.includes(t))).map(([k])=>k);
return {busy, impacted};
